"use strict";document.addEventListener("DOMContentLoaded",function(){var t=document.getElementById("text-input"),e=document.getElementById("btn-clear"),n=document.getElementById("count-chars"),o=document.getElementById("count-chars-no-space"),c=document.getElementById("count-lines"),d=document.getElementById("count-words"),u=document.getElementById("count-bytes");function l(){var e=t.value;n.textContent=e.length;var l=e.replace(/[\s\u3000]/g,"");o.textContent=l.length,c.textContent=""===e?0:e.split("\n").length;var a=e.trim();if(""===a)d.textContent=0;else{var r=a.split(/\s+/);d.textContent=r.length}var m=new TextEncoder;u.textContent=m.encode(e).length}t.addEventListener("input",l),e.addEventListener("click",function(){t.value="",l()}),l()});